const fs = require('fs');

function computeLoanMetrics(loan) {
    const principal = loan.principal;
    const annualRatePct = loan.annual_rate_pct;
    const termMonths = loan.term_months;
    const originationFee = loan.origination_fee;

    const monthlyRate = annualRatePct / 100 / 12;

    let monthlyPayment;
    if (monthlyRate === 0) {
        monthlyPayment = principal / termMonths;
    } else {
        const factor = Math.pow(1 + monthlyRate, termMonths);
        monthlyPayment = (principal * monthlyRate * factor) / (factor - 1);
    }

    monthlyPayment = Math.round(monthlyPayment * 100) / 100;
    const totalInterest = Math.round((monthlyPayment * termMonths - principal) * 100) / 100;
    const totalPaid = Math.round((principal + totalInterest + originationFee) * 100) / 100;

    const discrepancies = [];

    const statedMonthlyPayment = loan.stated_monthly_payment;
    const statedTotalInterest = loan.stated_total_interest;
    const statedTotalPaid = loan.stated_total_paid;

    if (monthlyPayment !== statedMonthlyPayment) {
        discrepancies.push({
            field: 'monthly_payment',
            stated: statedMonthlyPayment,
            computed: monthlyPayment,
            delta: Math.round((monthlyPayment - statedMonthlyPayment) * 100) / 100
        });
    }

    if (totalInterest !== statedTotalInterest) {
        discrepancies.push({
            field: 'total_interest',
            stated: statedTotalInterest,
            computed: totalInterest,
            delta: Math.round((totalInterest - statedTotalInterest) * 100) / 100
        });
    }

    if (totalPaid !== statedTotalPaid) {
        discrepancies.push({
            field: 'total_paid',
            stated: statedTotalPaid,
            computed: totalPaid,
            delta: Math.round((totalPaid - statedTotalPaid) * 100) / 100
        });
    }

    return {
        loan_id: loan.loan_id,
        lender: loan.lender,
        computed: {
            monthly_payment: monthlyPayment,
            total_interest: totalInterest,
            total_paid: totalPaid
        },
        discrepancies: discrepancies,
        valid: discrepancies.length === 0
    };
}

const loanData = fs.readFileSync('/var/folders/1q/vdr_cj816z314xnj3bp7w_wr0000gn/T/capture-loan_calculator-h79pakv0/loan_calculator/sample_inputs/loan_011.json', 'utf8');
const loan = JSON.parse(loanData);

const result = computeLoanMetrics(loan);

fs.writeFileSync('/var/folders/1q/vdr_cj816z314xnj3bp7w_wr0000gn/T/capture-loan_calculator-h79pakv0/loan_calculator/output.json', JSON.stringify(result, null, 2));

console.log(JSON.stringify(result, null, 2));

